import React, { Component } from "react";
import defaultImg from "./image/default.jpg";
// import background1 from ".";
import background1 from '../../image/background1.jpg'
import "./index.css";

class Application extends Component {
  constructor(props) {
    super(props);

    const saveProfile = JSON.parse(localStorage.getItem("userProfile")) || {};
    const saveImg = localStorage.getItem("profileImg");

    this.state = {
      firstName: saveProfile.firstName || "",
      lastName: saveProfile.lastName || "",
      age: saveProfile.age || "",
      email: saveProfile.email || "",
      mobile: saveProfile.mobile || "",
      height: saveProfile.height || "",
      institute: saveProfile.institute || "",
      bloodGroup: saveProfile.bloodGroup || "",
      district: saveProfile.district || "",
      birthday: saveProfile.birthday || "",
      gender: saveProfile.gender || "",
      profileImg: saveImg || defaultImg,
    };

    this.fileInputRef = React.createRef();
  }

  handleChange = (event) => {
    const { name, value } = event.target;
    this.setState({ [name]: value });
  };

  handleProfileChange = (event) => {
    const file = event.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        localStorage.setItem("profileImg", e.target.result);
        this.setState({ profileImg: e.target.result });
      };
      reader.readAsDataURL(file);
    }
  };

  handleSubmit = (event) => {
    event.preventDefault();
    localStorage.setItem("userProfile", JSON.stringify(this.state));
    alert("✅ Profile updated successfully!");
  };

  render() {
    return (
      <div
        className="profile-background"
        style={{ backgroundImage: `url(${background1})` }}

      >
        <div className="profile-card transparent-card">
          <h3 className="text-center mb-4">Edit Profile</h3>

          {/* Profile Image */}
          <div className="text-center mb-3">
            <img
              src={this.state.profileImg}
              alt="Profile"
              className="profile-pic"
            />
            <br />
            <button
              className="btn btn-sm btn-outline-light mt-2"
              onClick={() => this.fileInputRef.current.click()}
            >
              Change Image
            </button>
            <input
              type="file"
              accept="image/*"
              style={{ display: "none" }}
              ref={this.fileInputRef}
              onChange={this.handleProfileChange}
            />
          </div>

          {/* Profile Form */}
          <form onSubmit={this.handleSubmit}>
            <div className="row mb-3">
              <div className="col">
                <label>First Name</label>
                <input
                  type="text"
                  className="form-control"
                  name="firstName"
                  value={this.state.firstName}
                  onChange={this.handleChange}
                />
              </div>
              <div className="col">
                <label>Last Name</label>
                <input
                  type="text"
                  className="form-control"
                  name="lastName"
                  value={this.state.lastName}
                  onChange={this.handleChange}
                />
              </div>
            </div>

            <div className="row mb-3">
              <div className="col">
                <label>Age</label>
                <input
                  type="number"
                  className="form-control"
                  name="age"
                  value={this.state.age}
                  onChange={this.handleChange}
                />
              </div>
              <div className="col">
                <label>Gender</label>
                <input
                  type="text"
                  className="form-control"
                  name="gender"
                  value={this.state.gender}
                  onChange={this.handleChange}
                />
              </div>
            </div>

            <div className="mb-3">
              <label>Email</label>
              <input
                type="email"
                className="form-control"
                name="email"
                value={this.state.email}
                onChange={this.handleChange}
              />
            </div>

            <div className="mb-3">
              <label>Mobile</label>
              <input
                type="text"
                className="form-control"
                name="mobile"
                value={this.state.mobile}
                onChange={this.handleChange}
              />
            </div>

            <div className="row mb-3">
              <div className="col">
                <label>Height</label>
                <input
                  type="text"
                  className="form-control"
                  name="height"
                  value={this.state.height}
                  onChange={this.handleChange}
                />
              </div>
              <div className="col">
                <label>Blood Group</label>
                <input
                  type="text"
                  className="form-control"
                  name="bloodGroup"
                  value={this.state.bloodGroup}
                  onChange={this.handleChange}
                />
              </div>
            </div>

            <div className="mb-3">
              <label>Institute</label>
              <input
                type="text"
                className="form-control"
                name="institute"
                value={this.state.institute}
                onChange={this.handleChange}
              />
            </div>

            <div className="row mb-3">
              <div className="col">
                <label>District</label>
                <input
                  type="text"
                  className="form-control"
                  name="district"
                  value={this.state.district}
                  onChange={this.handleChange}
                />
              </div>
              <div className="col">
                <label>Birthday</label>
                <input
                  type="text"
                  className="form-control"
                  name="birthday"
                  placeholder="DD-MM-YYYY"
                  value={this.state.birthday}
                  onChange={this.handleChange}
                />
              </div>
            </div>

            <button type="submit" className="btn btn-success w-100">
              Save Changes
            </button>
          </form>
        </div>
      </div>
    );
  }
}

export default Application;
